  it("includes hint for INVALID_FORMAT", () => {
    const error = createWSError("INVALID_FORMAT", "Invalid");
    expect(error.hint).toBeDefined();
    expect(error.example).toBeDefined();
  });

  it("includes docs link for documented errors", () => {
    const error = createWSError("FORBIDDEN", "Access denied");
    expect(error.docs).toContain("flywheel.dev");
  });
});
```

